module.render:
    const esc = (s) => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
    const author = String(args.author || '').trim();
    const source = String(args.source || '').trim();
    const alignRaw = String(args.align || 'left').toLowerCase();
    const align = (['left', 'center', 'right'].indexOf(alignRaw) >= 0) ? alignRaw : 'left';
    const alignCss = (align === 'left') ? 'inherit' : align;
    const accent = (args.accent && String(args.accent).trim()) || 'var(--accent-color)';
    const bg = (args.bg && String(args.bg).trim()) || '#f4f6f7';
    const textcolor = (args.textcolor && String(args.textcolor).trim()) || '#34495e';
    const contentStr = sections[0] ? sections[0].trim() : '';
    return `\n\n
<div class="mdp-mod-quote" style="--quote-accent:${accent}; --quote-bg:${bg}; --quote-text:${textcolor}; --quote-align:${alignCss};">
<div class="mdp-quote-icon">“</div>
<div class="mdp-quote-content">

${contentStr}

</div>
${author ? `<div class="mdp-quote-author">— ${esc(author)}</div>` : ''}
${source ? `<div class="mdp-quote-source">${esc(source)}</div>` : ''}
</div>
\n\n`;
